--
-- Table structure for table `comunicado`
--

DROP TABLE IF EXISTS `comunicado`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `comunicado` (
  `id` int NOT NULL AUTO_INCREMENT,
  `plataforma_id` int DEFAULT NULL,
  `tipo_comunicado_id` int DEFAULT NULL,
  `serie_id` int DEFAULT NULL,
  `consecutivo_num` varchar(20) DEFAULT NULL,
  `asunto_final` varchar(200) DEFAULT NULL,
  `html_final` text,
  `descripcion` text,
  `afectacion` varchar(255) DEFAULT NULL,
  `solucion_aplicada` text,
  `analista_id` int DEFAULT NULL,
  `servicio_id` int DEFAULT NULL,
  `estado` varchar(50) DEFAULT NULL,
  `fecha_creacion` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `fecha_envio` timestamp NULL DEFAULT NULL,
  `escalado` tinyint(1) DEFAULT '0',
  `requiere_aprobacion` tinyint(1) DEFAULT '0',
  `aprobado_por` int DEFAULT NULL,
  `html_cierre` text,
  `asunto_cierre` varchar(200) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `plataforma_id` (`plataforma_id`),
  KEY `tipo_comunicado_id` (`tipo_comunicado_id`),
  KEY `serie_id` (`serie_id`),
  KEY `analista_id` (`analista_id`),
  KEY `servicio_id` (`servicio_id`),
  KEY `fk_aprobado` (`aprobado_por`),
  CONSTRAINT `comunicado_ibfk_1` FOREIGN KEY (`plataforma_id`) REFERENCES `plataforma` (`id`),
  CONSTRAINT `comunicado_ibfk_2` FOREIGN KEY (`tipo_comunicado_id`) REFERENCES `tipo_comunicado` (`id`),
  CONSTRAINT `comunicado_ibfk_3` FOREIGN KEY (`serie_id`) REFERENCES `serie` (`id`),
  CONSTRAINT `comunicado_ibfk_4` FOREIGN KEY (`analista_id`) REFERENCES `analista` (`id`),
  CONSTRAINT `comunicado_ibfk_5` FOREIGN KEY (`servicio_id`) REFERENCES `servicio` (`id`),
  CONSTRAINT `fk_aprobado` FOREIGN KEY (`aprobado_por`) REFERENCES `analista` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=45 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

