LOCK TABLES `comunicado` WRITE;
/*!40000 ALTER TABLE `comunicado` DISABLE KEYS */;
INSERT INTO `comunicado` VALUES (1,1,1,1,'CMO-1','CMO-1 Comunicado de Novedad con ACQUIRING RS2','<!DOCTYPE html>\n<html lang=\"es\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Movii - Comunicado de Novedad Operativa</title>\n  <style>\n    body, table, td, a { -webkit-text-size-adjust: 100%; -ms-text-size-adjust: 100%; }\n    table, td { mso-table-lspace: 0pt; mso-table-rspace: 0pt; }\n    img { -ms-interpolation-mode: bicubic; }\n  </style>\n</head>\n<body style=\"margin: 0; padding: 0; background-color: #F2F3F7; font-family: Arial, Helvetica, sans-serif; color: #10004F;\">\n  <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\" style=\"background-color: #F2F3F7; padding: 20px 10px;\">\n    <tr>\n      <td align=\"center\">\n        <!-- Contenedor Principal Blanco -->\n        <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"600\" style=\"background-color: #ffffff; border-radius: 8px; overflow: hidden; max-width: 600px; width: 100%; box-shadow: 0 4px 15px rgba(16, 0, 79, 0.05);\">\n          \n          <!-- Cabecera -->\n          <tr>\n            <td style=\"background-color: #F5F5F5; padding: 30px; border-bottom: 3px solid #d51b5d;\">\n              <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n                <tr>\n                  <td align=\"left\">\n                    <img src=\"https://i.ibb.co/rG81HGky/Logo-movii-magenta.png\" alt=\"MOVII\" height=\"36\" style=\"display: block; height: 36px; width: auto;\">\n                  </td>\n                  <td align=\"right\" style=\"font-size: 11px; color: #2bbcee; font-weight: bold; text-transform: uppercase; line-height: 1.4;\">\n                    Comunicado de Novedad Operativa<br>\n                    <span style=\"color: #10004F;\">ID: CMO-1</span>\n                  </td>\n                </tr>\n              </table>\n            </td>\n          </tr>\n\n          <!-- Cuerpo del Correo -->\n          <tr>\n            <td style=\"padding: 30px;\">\n              <h1 style=\"font-size: 22px; margin-top: 0; margin-bottom: 20px; color: #10004F;\">Notificación de Interrupción Parcial de Servicio</h1>\n              \n              <!-- Caja de Detalles del Evento -->\n              <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\" style=\"background-color: #F5F5F5; border-left: 4px solid #d51b5d; border-radius: 4px; margin-bottom: 25px;\">\n                <tr>\n                  <td style=\"padding: 20px;\">\n                    <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n                      <tr>\n                        <td align=\"left\" style=\"font-weight: bold; font-size: 16px; padding-bottom: 20px; color: #10004F;\">Detalles del Evento</td>\n                        <td align=\"right\" style=\"padding-bottom: 20px;\">\n                          <!-- Etiqueta \"Activo\" -->\n                          <span style=\"background-color: #d51b5d; color: #ffffff; font-size: 12px; padding: 4px 12px; border-radius: 12px; font-weight: bold;\">Activo</span>\n                        </td>\n                      </tr>\n                      <tr>\n                        <td width=\"50%\" style=\"padding-bottom: 15px; padding-right: 10px;\">\n                          <p style=\"margin: 0 0 4px 0; font-size: 10px; color: #2bbcee; font-weight: bold; text-transform: uppercase;\">FECHA DEL COMUNICADO</p>\n                          <p style=\"margin: 0; font-size: 14px; font-weight: bold; color: #10004F;\">25 Abr 2026 - 06:50 PM (COT)</p>\n                        </td>\n                        <td width=\"50%\" style=\"padding-bottom: 15px;\">\n                          <p style=\"margin: 0 0 4px 0; font-size: 10px; color: #2bbcee; font-weight: bold; text-transform: uppercase;\">INICIO DE LA NOVEDAD</p>\n                          <p style=\"margin: 0; font-size: 14px; font-weight: bold; color: #10004F;\">25 Abr 2026 - 06:43 PM (COT)</p>\n                        </td>\n                      </tr>\n                      <tr>\n                        <td colspan=\"2\" style=\"padding-bottom: 15px;\">\n                          <p style=\"margin: 0 0 4px 0; font-size: 10px; color: #2bbcee; font-weight: bold; text-transform: uppercase;\">SERVICIO AFECTADO</p>\n                          <p style=\"margin: 0; font-size: 14px; font-weight: bold; color: #10004F;\">ACQUIRING - RS2</p>\n                        </td>\n                      </tr>\n                      <tr>\n                        <td colspan=\"2\">\n                          <p style=\"margin: 0 0 4px 0; font-size: 10px; color: #2bbcee; font-weight: bold; text-transform: uppercase;\">DESCRIPCIÓN OPERATIVA</p>\n                          <p style=\"margin: 0; font-size: 14px; line-height: 1.5; color: #10004F;\">Se informa que la entidad RS2 presenta novedad en el servicio de ACQUIRING. La incidencia ya ha sido escalada. Una vez presente normalidad les informaremos. Agradecemos su comprensión.</p>\n                        </td>\n                      </tr>\n                    </table>\n                  </td>\n                </tr>\n              </table>\n\n              <p style=\"font-size: 14px; line-height: 1.6; margin-bottom: 25px; color: #10004F;\">Agradecemos su comprensión mientras gestionamos esta incidencia tecnológica. Se emitirá una actualización una vez confirmemos la estabilización del flujo afectado.</p>\n              \n              <p style=\"font-size: 14px; line-height: 1.5; margin: 0; color: #10004F;\">\n                Atentamente,<br>\n                <strong style=\"font-size: 15px; display: block; margin-top: 4px; color: #d51b5d;\">Equipo de Monitoreo</strong>\n              </p>\n            </td>\n          </tr>\n\n          <!-- Pie de página -->\n          <tr>\n            <td style=\"background-color: #F5F5F5; padding: 25px 30px; border-top: 2px solid #F2F3F7;\">\n              <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n                <tr>\n                  <td width=\"60\" align=\"left\" valign=\"middle\">\n                    <img src=\"https://i.ibb.co/rG81HGky/Logo-movii-magenta.png\" alt=\"MOVII\" height=\"36\" style=\"display: block; height: 36px; width: auto; opacity: 0.85;\">\n                  </td>\n                  <td align=\"left\" valign=\"middle\" style=\"padding-left: 10px;\">\n                    <p style=\"margin: 0 0 2px 0; font-size: 13px; font-weight: bold; color: #10004F;\">Dirección de Operaciones IT</p>\n                    <p style=\"margin: 0; font-size: 11px; color: #2bbcee; font-weight: bold;\">Movii Operational Authority</p>\n                  </td>\n                  <td align=\"right\" valign=\"middle\" width=\"220\">\n                    <p style=\"margin: 0; font-size: 9px; color: #10004F; text-transform: uppercase; line-height: 1.4; opacity: 0.7;\">\n                      © 2026 Movii Operational Authority.<br>Confidentiality intended.\n                    </p>\n                  </td>\n                </tr>\n              </table>\n            </td>\n          </tr>\n\n        </table>\n      </td>\n    </tr>\n  </table>\n</body>\n</html>','Se informa que la entidad RS2 presenta novedad en el servicio de ACQUIRING. La incidencia ya ha sido escalada. Una vez presente normalidad les informaremos. Agradecemos su comprensión.','Afecta Disponibilidad','',3,1,'Cerrado','2026-04-25 23:43:00','2026-04-26 04:46:00',0,0,NULL,NULL,NULL),(2,2,3,1,'CMO-2','CMO-2 - Comunicado de novedad con el cliente - EFECTY LTDA sin saldo disponible','<!DOCTYPE html>\n<html lang=\"es\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\">\n<title>Aviso de Saldo Insuficiente - Movii</title>\n</head>\n<body style=\"margin:0;padding:0;background-color:#F2F3F7;font-family:\'Inter\',Arial,sans-serif;\">\n\n<div style=\"display:none;max-height:0;overflow:hidden;font-size:1px;color:#F2F3F7;\">\n  Su cuenta no cuenta con saldo suficiente. Por favor recargue para continuar operando.\n</div>\n\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#F2F3F7;\">\n  <tr>\n    <td align=\"center\" style=\"padding:32px 16px;\">\n\n      <table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"max-width:600px;width:100%;background-color:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 4px 15px rgba(16, 0, 79, 0.05);\">\n\n        <tr>\n          <td style=\"background-color:#F5F5F5;padding:24px 32px; border-bottom: 3px solid #d51b5d;\">\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n              <tr>\n                <td style=\"vertical-align:middle;\">\n                    <img src=\"https://i.ibb.co/HTy6GFMP/MOVii-RED-logo-magenta.png\" alt=\"MOVII\" height=\"36\" style=\"display: block; height: 36px; width: auto;\">\n                </td>\n                <td align=\"right\" style=\"vertical-align:middle;\">\n                  <span style=\"font-family:\'Inter\',Arial,sans-serif;font-size:0.75rem;font-weight:bold;color:#2bbcee;letter-spacing:0.08em;text-transform:uppercase;\">ID del Sistema: <span style=\"color:#10004F;\">CMO-2</span></span>\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <tr>\n          <td style=\"background-color:#ffffff;padding:40px 32px 32px 32px;\">\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n              <tr>\n                <td>\n                  <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n                    <tr>\n                      <td style=\"vertical-align:top;padding-right:12px;padding-top:2px;\">\n                        <div style=\"width:28px;height:28px;background-color:#d51b5d;border-radius:50%;display:inline-block;text-align:center;line-height:28px;\">\n                          <span style=\"color:#ffffff;font-size:17px;font-weight:bold;font-family:Arial,sans-serif;\">!</span>\n                        </div>\n                      </td>\n                      <td style=\"vertical-align:top;\">\n                        <h1 style=\"margin:0;font-family:\'Manrope\',\'Inter\',Arial,sans-serif;font-size:2rem;font-weight:800;color:#10004F;line-height:1.15;letter-spacing:-0.5px;\">\n                          Aviso de Saldo<br>Insuficiente\n                        </h1>\n                      </td>\n                    </tr>\n                  </table>\n                </td>\n              </tr>\n              <tr>\n                <td style=\"padding-top:20px;text-align:center;vertical-align:middle;\">\n                  <p style=\"margin:0 auto;font-family:\'Inter\',Arial,sans-serif;font-size:0.9375rem;color:#10004F;line-height:1.7;max-width:480px;text-align:justify;\">\n                    Se presenta novedad con el cliente <strong>EFECTY LTDA</strong> por saldo insuficiente. La novedad ha sido escalada, apenas tengamos un avance les estaremos informando. Agradecemos su comprensión.\n                  </p>\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <tr>\n          <td style=\"padding:0 32px 32px 32px; background-color: #ffffff;\">\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n              <tr>\n                <td width=\"50%\" style=\"vertical-align:top;padding-right:8px;\">\n                  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#F5F5F5;border-radius:8px;overflow:hidden;height:100%;\">\n                    <tr>\n                      <td style=\"padding:24px;\">\n                        <p style=\"margin:0 0 10px 0;font-family:\'Inter\',Arial,sans-serif;font-size:0.75rem;font-weight:bold;color:#2bbcee;letter-spacing:0.1em;text-transform:uppercase;\">ESTADO DE OPERACIÓN</p>\n                        <div style=\"display:inline-block;background-color:#d51b5d;border-radius:9999px;padding:5px 14px;\">\n                          <span style=\"font-family:\'Inter\',Arial,sans-serif;font-size:0.8125rem;font-weight:bold;color:#ffffff;\">Sin Saldo</span>\n                        </div>\n                        <p style=\"margin:20px 0 4px 0;font-family:\'Inter\',Arial,sans-serif;font-size:0.75rem;font-weight:bold;color:#2bbcee;letter-spacing:0.1em;text-transform:uppercase;\">CLIENTE:</p>\n                        <p style=\"margin:0;font-family:\'Manrope\',\'Inter\',Arial,sans-serif;font-size:1.125rem;font-weight:bold;color:#10004F;letter-spacing:0.02em;\">EFECTY LTDA</p>\n                      </td>\n                    </tr>\n                  </table>\n                </td>\n                <td width=\"50%\" style=\"vertical-align:top;padding-left:8px;\">\n                  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#F5F5F5;border-radius:8px;overflow:hidden;height:100%;\">\n                    <tr>\n                      <td style=\"padding:24px;text-align:center;vertical-align:middle;\">\n                        <div style=\"width:48px;height:48px;background-color:#ffffff;border: 1px solid #F2F3F7;border-radius:10px;margin:0 auto 16px auto;text-align:center;line-height:48px;\">\n                          <span style=\"font-size:22px;\">⚠️</span>\n                        </div>\n                        <p style=\"margin:0;font-family:\'Inter\',Arial,sans-serif;font-size:0.9375rem;color:#10004F;line-height:1.6;\">\n                          Recargue su cuenta para reactivar sus operaciones.\n                        </p>\