INSERT INTO `plantilla` VALUES (1,1,1,1,'Novedad movii','<!DOCTYPE html>\n<html lang=\"es\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Movii - Comunicado de Novedad Operativa</title>\n  <style>\n    body, table, td, a { -webkit-text-size-adjust: 100%; -ms-text-size-adjust: 100%; }\n    table, td { mso-table-lspace: 0pt; mso-table-rspace: 0pt; }\n    img { -ms-interpolation-mode: bicubic; }\n  </style>\n</head>\n<body style=\"margin: 0; padding: 0; background-color: #F2F3F7; font-family: Arial, Helvetica, sans-serif; color: #10004F;\">\n  <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\" style=\"background-color: #F2F3F7; padding: 20px 10px;\">\n    <tr>\n      <td align=\"center\">\n        <!-- Contenedor Principal Blanco -->\n        <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"600\" style=\"background-color: #ffffff; border-radius: 8px; overflow: hidden; max-width: 600px; width: 100%; box-shadow: 0 4px 15px rgba(16, 0, 79, 0.05);\">\n          \n          <!-- Cabecera -->\n          <tr>\n            <td style=\"background-color: #F5F5F5; padding: 30px; border-bottom: 3px solid #d51b5d;\">\n              <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n                <tr>\n                  <td align=\"left\">\n                    <img src=\"https://res.cloudinary.com/bayehcompany/image/upload/v1778112472/dozewlylntjhfklp2bwj.png\" alt=\"MOVII\" height=\"36\" style=\"display: block; height: 36px; width: auto;\">\n                  </td>\n                  <td align=\"right\" style=\"font-size: 11px; color: #d51b5d; font-weight: bold; text-transform: uppercase; line-height: 1.4;\">\n                    Comunicado de Novedad Operativa<br>\n                    <span style=\"color: #10004F;\">ID: {{ consecutivo }}</span>\n                  </td>\n                </tr>\n              </table>\n            </td>\n          </tr>\n\n          <!-- Cuerpo del Correo -->\n          <tr>\n            <td style=\"padding: 30px;\">\n              <h1 style=\"font-size: 22px; margin-top: 0; margin-bottom: 20px; color: #10004F;\">Notificación de Interrupción Parcial de Servicio</h1>\n              \n              <!-- Caja de Detalles del Evento -->\n              <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\" style=\"background-color: #F5F5F5; border-left: 4px solid #d51b5d; border-radius: 4px; margin-bottom: 25px;\">\n                <tr>\n                  <td style=\"padding: 20px;\">\n                    <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n                      <tr>\n                        <td align=\"left\" style=\"font-weight: bold; font-size: 16px; padding-bottom: 20px; color: #10004F;\">Detalles del Evento</td>\n                        <td align=\"right\" style=\"padding-bottom: 20px;\">\n                          <!-- Etiqueta \"Activo\" -->\n                          <span style=\"background-color: #d51b5d; color: #ffffff; font-size: 12px; padding: 4px 12px; border-radius: 12px; font-weight: bold;\">Activo</span>\n                        </td>\n                      </tr>\n                      <tr>\n                        <td width=\"50%\" style=\"padding-bottom: 15px; padding-right: 10px;\">\n                          <p style=\"margin: 0 0 4px 0; font-size: 10px; color: #d51b5d; font-weight: bold; text-transform: uppercase;\">FECHA DEL COMUNICADO</p>\n                          <p style=\"margin: 0; font-size: 14px; font-weight: bold; color: #10004F;\">{{ fecha_comunicado }}</p>\n                        </td>\n                        <td width=\"50%\" style=\"padding-bottom: 15px;\">\n                          <p style=\"margin: 0 0 4px 0; font-size: 10px; color: #d51b5d; font-weight: bold; text-transform: uppercase;\">INICIO DE LA NOVEDAD</p>\n                          <p style=\"margin: 0; font-size: 14px; font-weight: bold; color: #10004F;\">{{ fecha_inicio }}</p>\n                        </td>\n                      </tr>\n                      <tr>\n                        <td colspan=\"2\" style=\"padding-bottom: 15px;\">\n                          <p style=\"margin: 0 0 4px 0; font-size: 10px; color: #d51b5d; font-weight: bold; text-transform: uppercase;\">SERVICIO AFECTADO</p>\n                          <p style=\"margin: 0; font-size: 14px; font-weight: bold; color: #10004F;\">{{ servicio }}</p>\n                        </td>\n                      </tr>\n                      <tr>\n                        <td colspan=\"2\">\n                          <p style=\"margin: 0 0 4px 0; font-size: 10px; color: #d51b5d; font-weight: bold; text-transform: uppercase;\">DESCRIPCIÓN OPERATIVA</p>\n                          <p style=\"margin: 0; font-size: 14px; line-height: 1.5; color: #10004F;\">{{ descripcion }}</p>\n                        </td>\n                      </tr>\n                    </table>\n                  </td>\n                </tr>\n              </table>\n\n              <p style=\"font-size: 14px; line-height: 1.6; margin-bottom: 25px; color: #10004F;\">Agradecemos su comprensión mientras gestionamos esta incidencia tecnológica. Se emitirá una actualización una vez confirmemos la estabilización del flujo afectado.</p>\n              \n              <p style=\"font-size: 14px; line-height: 1.5; margin: 0; color: #10004F;\">\n                Atentamente,<br>\n                <strong style=\"font-size: 15px; display: block; margin-top: 4px; color: #d51b5d;\">Equipo de Monitoreo</strong>\n              </p>\n            </td>\n          </tr>\n\n          <!-- Pie de página -->\n          <tr>\n            <td style=\"background-color: #F5F5F5; padding: 25px 30px; border-top: 2px solid #F2F3F7;\">\n              <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n                <tr>\n                  <td width=\"60\" align=\"left\" valign=\"middle\">\n                    <img src=\"https://res.cloudinary.com/bayehcompany/image/upload/v1778112472/dozewlylntjhfklp2bwj.png\" alt=\"MOVII\" height=\"36\" style=\"display: block; height: 36px; width: auto; opacity: 0.85;\">\n                  </td>\n                  \n                  <td align=\"right\" valign=\"middle\" width=\"220\">\n                    <p style=\"margin: 0 0 6px 0; font-size: 9px; color: #d51b5d; text-transform: uppercase; font-weight: bold;\">\n                      <a href=\"#\" style=\"color: #d51b5d; text-decoration: none;\">Soporte</a> &nbsp;|&nbsp; <a href=\"#\" style=\"color: #d51b5d; text-decoration: none;\">3204688101</a> &nbsp;|&nbsp; <a href=\"#\" style=\"color: #d51b5d; text-decoration: none;\">Contáctenos</a>\n                    </p>\n                    <p style=\"margin: 0; font-size: 9px; color: #10004F; text-transform: uppercase; line-height: 1.4; opacity: 0.7;\">\n                      © Copyright MOVii, Todos los derechos reservados. 2026.<br>\n                    </p>\n                  </td>\n                </tr>\n              </table>\n            </td>\n          </tr>\n\n        </table>\n      </td>\n    </tr>\n  </table>\n</body>\n</html>',1,'2026-04-17 14:53:15'),(2,1,1,2,'Normalidad movii','<!DOCTYPE html>\n<html lang=\"es\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Movii - Comunicado de Normalidad</title>\n<style>\n  body, table, td, a { -webkit-text-size-adjust: 100%; -ms-text-size-adjust: 100%; }\n  table, td { mso-table-lspace: 0pt; mso-table-rspace: 0pt; }\n  img { -ms-interpolation-mode: bicubic; }\n</style>\n</head>\n<body style=\"margin: 0; padding: 0; background-color: #F2F3F7; font-family: Arial, Helvetica, sans-serif; color: #10004F;\">\n  <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\" style=\"background-color: #F2F3F7; padding: 20px 10px;\">\n    <tr>\n      <td align=\"center\">\n        <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"600\" style=\"background-color: #ffffff; border-radius: 8px; overflow: hidden; max-width: 600px; width: 100%; box-shadow: 0 4px 15px rgba(16, 0, 79, 0.05);\">\n          \n          <tr>\n            <td style=\"background-color: #F5F5F5; padding: 30px; border-bottom: 3px solid #2bbcee;\">\n              <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n                <tr>\n                  <td align=\"left\">\n                    <img src=\"https://res.cloudinary.com/bayehcompany/image/upload/v1778112472/dozewlylntjhfklp2bwj.png\" alt=\"MOVII\" height=\"36\" style=\"display: block; height: 36px; width: auto;\">\n                  </td>\n                  <td align=\"right\" style=\"font-size: 11px; color: #10004F; text-transform: uppercase; line-height: 1.4; font-weight: bold;\">\n                    ID del Sistema: {{ consecutivo }}<br><br>\n                    <span style=\"background-color: #2bbcee; color: #ffffff; padding: 6px 12px; border-radius: 12px; font-weight: bold; font-size: 11px; display: inline-block;\">\n                      &#10004; Normalidad Restablecida\n                    </span>\n                  </td>\n                </tr>\n              </table>\n            </td>\n          </tr>\n\n          <tr>\n            <td style=\"padding: 30px;\">\n              <h1 style=\"font-size: 22px; margin-top: 0; margin-bottom: 15px; color: #10004F;\">Comunicado de Restablecimiento de Servicio</h1>\n              <p style=\"font-size: 14px; line-height: 1.6; color: #10004F; margin-bottom: 25px;\">\n                Estimado equipo,<br><br>\n                Nos dirigimos a ustedes para informar que la incidencia reportada previamente ha sido solucionada y los servicios operativos han regresado a su estado de normalidad. A continuación, presentamos los detalles del evento.\n              </p>\n              \n              <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\" style=\"background-color: #F5F5F5; border-left: 4px solid #2bbcee; border-radius: 6px; margin-bottom: 25px;\">\n                <tr>\n                  <td style=\"padding: 20px;\">\n                    <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n                      <tr>\n                        <td width=\"50%\" style=\"padding-bottom: 20px;\" valign=\"top\" colspan=\"2\">\n                          <p style=\"margin: 0 0 4px 0; font-size: 10px; color: #2bbcee; font-weight: bold; text-transform: uppercase;\">Servicio Afectado</p>\n                          <p style=\"margin: 0; font-size: 14px; color: #10004F; font-weight: bold;\">\n                            {{ servicio }}\n                            <span style=\"background-color: #2bbcee; color: #ffffff; font-size: 10px; padding: 4px 8px; border-radius: 10px; margin-left: 6px;\">Restablecido</span>\n                          </p>\n                        </td>\n                      </tr>\n                      <tr>\n                        <td width=\"50%\" style=\"padding-bottom: 20px; padding-right: 10px;\" valign=\"top\">\n                          <p style=\"margin: 0 0 4px 0; font-size: 10px; color: #2bbcee; font-weight: bold; text-transform: uppercase;\">Inicio de Novedad</p>\n                          <p style=\"margin: 0; font-size: 14px; font-weight: bold; color: #10004F;\">{{ fecha_inicio }}</p>\n                        </td>\n                        <td width=\"50%\" style=\"padding-bottom: 20px;\" valign=\"top\">\n                          <p style=\"margin: 0 0 4px 0; font-size: 10px; color: #2bbcee; font-weight: bold; text-transform: uppercase;\">Fin de Novedad</p>\n                          <p style=\"margin: 0; font-size: 14px; font-weight: bold; color: #10004F;\">{{ fecha_cierre }}</p>\n                        </td>\n                      </tr>\n                      <tr>\n                        <td colspan=\"2\" style=\"padding-bottom: 20px;\">\n                          <div style=\"background-color: #ffffff; padding: 15px; border-radius: 4px; border: 1px solid #F2F3F7;\">\n                            <p style=\"margin: 0 0 4px 0; font-size: 10px; color: #2bbcee; font-weight: bold; text-transform: uppercase;\">Descripción de la Novedad Original</p>\n                            <p style=\"margin: 0; font-size: 13px; color: #10004F; line-height: 1.5;\">{{ descripcion_novedad }}</p>\n                          </div>\n                        </td>\n                      </tr>\n                      <tr>\n                        <td colspan=\"2\" style=\"padding-top: 5px;\">\n                          <p style=\"margin: 0 0 4px 0; font-size: 10px; color: #2bbcee; font-weight: bold; text-transform: uppercase;\">Tiempo Transcurrido</p>\n                          <p style=\"margin: 0; font-size: 14px; color: #10004F; font-weight: bold;\">{{ tiempo_transcurrido }}</p>\n                        </td>\n                      </tr>\n                    </table>\n                  </td>\n                </tr>\n              </table>\n\n              <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\" style=\"background-color: #F5F5F5; border-left: 4px solid #2bbcee; border-radius: 4px; margin-bottom: 30px;\">\n                <tr>\n                  <td style=\"padding: 20px;\">\n                    <h3 style=\"margin-top: 0; margin-bottom: 10px; font-size: 16px; color: #2bbcee;\">&#10004; Descripción de la Normalidad</h3>\n                    <p style=\"margin: 0; font-size: 14px; line-height: 1.6; color: #10004F;\">{{ descripcion_cierre }}</p>\n                  </td>\n                </tr>\n              </table>\n\n              <p style=\"font-size: 14px; line-height: 1.5; margin: 0; color: #10004F;\">\n                Atentamente,<br>\n                <strong style=\"font-size: 15px; display: block; margin-top: 4px; color: #d51b5d;\">Equipo de Monitoreo</strong>\n                <span style=\"font-size: 12px; color: #2bbcee;\">Centro de Control y Monitoreo de Servicios</span>\n              </p>\n            </td>\n          </tr>\n\n          <tr>\n            <td style=\"background-color: #F5F5F5; padding: 25px 30px; border-top: 2px solid #F2F3F7;\">\n              <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n                <tr>\n                  <td width=\"60\" align=\"left\" valign=\"middle\">\n                    <img src=\"https://res.cloudinary.com/bayehcompany/image/upload/v1778112472/dozewlylntjhfklp2bwj.png\" alt=\"MOVII\" height=\"36\" style=\"display: block; height: 36px; width: auto; opacity: 0.85;\">\n                  </td>\n                  \n                  <td align=\"right\" valign=\"middle\" width=\"220\">\n                    <p style=\"margin: 0 0 6px 0; font-size: 9px; color: #d51b5d; text-transform: uppercase; font-weight: bold;\">\n                      <a href=\"#\" style=\"color: #d51b5d; text-decoration: none;\">Soporte</a> &nbsp;|&nbsp; <a href=\"#\" style=\"color: #d51b5d; text-decoration: none;\">3204688101</a> &nbsp;|&nbsp; <a href=\"#\" style=\"color: #d51b5d; text-decoration: none;\">Contáctenos</a>\n                    </p>\n                    <p style=\"margin: 0; font-size: 9px; color: #10004F; text-transform: uppercase; line-height: 1.4; opacity: 0.7;\">\n                      © Copyright MOVii, Todos los derechos reservados. 2026.<br>\n                    </p>\n                  </td>\n                </tr>\n              </table>\n            </td>\n          </tr>\n\n        </table>\n      </td>\n    </tr>\n  </table>\n</body>\n</html>',1,'2026-04-17 14:53:15'),(3,2,3,1,'Plantilla Sin Saldo','<!DOCTYPE html>\n<html lang=\"es\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\">\n<title>Aviso de Saldo Insuficiente - Movii</title>\n</head>\n<body style=\"margin:0;padding:0;background-color:#F2F3F7;font-family:\'Inter\',Arial,sans-serif;\">\n\n<div style=\"display:none;max-height:0;overflow:hidden;font-size:1px;color:#F2F3F7;\">\n  Su cuenta no cuenta con saldo suficiente. Por favor recargue para continuar operando.\n</div>\n\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#F2F3F7;\">\n  <tr>\n    <td align=\"center\" style=\"padding:32px 16px;\">\n\n      <table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"max-width:600px;width:100%;background-color:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 4px 15px rgba(16, 0, 79, 0.05);\">\n\n        <tr>\n          <td style=\"background-color:#F5F5F5;padding:24px 32px; border-bottom: 3px solid #d51b5d;\">\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n              <tr>\n                <td style=\"vertical-align:middle;\">\n                    <img src=\"https://res.cloudinary.com/bayehcompany/image/upload/v1778112472/snofqs7tahii7enujzao.png\" alt=\"MOVII\" height=\"36\" style=\"display: block; height: 36px; width: auto;\">\n                </td>\n                <td align=\"right\" style=\"vertical-align:middle;\">\n                  <span style=\"font-family:\'Inter\',Arial,sans-serif;font-size:0.75rem;font-weight:bold;color:#2bbcee;letter-spacing:0.08em;text-transform:uppercase;\">ID del Sistema: <span style=\"color:#10004F;\">{{ consecutivo }}</span></span>\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <tr>\n          <td style=\"background-color:#ffffff;padding:40px 32px 32px 32px;\">\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n              <tr>\n                <td>\n                  <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n                    <tr>\n                      <td style=\"vertical-align:top;padding-right:12px;padding-top:2px;\">\n                        <div style=\"width:28px;height:28px;background-color:#d51b5d;border-radius:50%;display:inline-block;text-align:center;line-height:28px;\">\n                          <span style=\"color:#ffffff;font-size:17px;font-weight:bold;font-family:Arial,sans-serif;\">!</span>\n                        </div>\n                      </td>\n                      <td style=\"vertical-align:top;\">\n                        <h1 style=\"margin:0;font-family:\'Manrope\',\'Inter\',Arial,sans-serif;font-size:2rem;font-weight:800;color:#10004F;line-height:1.15;letter-spacing:-0.5px;\">\n                          Aviso de Saldo<br>Insuficiente\n                        </h1>\n                      </td>\n                    </tr>\n                  </table>\n                </td>\n              </tr>\n              <tr>\n                <td style=\"padding-top:20px;text-align:center;vertical-align:middle;\">\n                  <p style=\"margin:0 auto;font-family:\'Inter\',Arial,sans-serif;font-size:0.9375rem;color:#10004F;line-height:1.7;max-width:480px;text-align:justify;\">\n                    Se presenta novedad con el cliente <strong>{{cliente}}</strong> por saldo insuficiente. La novedad ha sido escalada, apenas tengamos un avance les estaremos informando. Agradecemos su comprensión.\n                  </p>\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <tr>\n          <td style=\"padding:0 32px 32px 32px; background-color: #ffffff;\">\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n              <tr>\n                <td width=\"50%\" style=\"vertical-align:top;padding-right:8px;\">\n                  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color